import{_ as o,o as t,c as a,ae as n}from"./chunks/framework.B6gjLfeO.js";const _=JSON.parse('{"title":"网络折腾血泪史：透明代理与 407 报错大坑","description":"","frontmatter":{},"headers":[],"relativePath":"tools/network-pitfalls.md","filePath":"tools/network-pitfalls.md"}'),r={name:"tools/network-pitfalls.md"};function s(l,e,c,d,i,p){return t(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="网络折腾血泪史-透明代理与-407-报错大坑" tabindex="-1">网络折腾血泪史：透明代理与 407 报错大坑 <a class="header-anchor" href="#网络折腾血泪史-透明代理与-407-报错大坑" aria-label="Permalink to &quot;网络折腾血泪史：透明代理与 407 报错大坑&quot;">​</a></h1><p>在折腾局域网全屋科学上网（透明代理）的过程中，我们遇到过几个极其隐蔽的坑，这里复盘分享一下，希望能帮你少走弯路。</p><h2 id="_1-openclash-局域网共享的-407-刺客" tabindex="-1">1. OpenClash 局域网共享的 &quot;407&quot; 刺客 <a class="header-anchor" href="#_1-openclash-局域网共享的-407-刺客" aria-label="Permalink to &quot;1. OpenClash 局域网共享的 &quot;407&quot; 刺客&quot;">​</a></h2><p><strong>场景还原</strong>： 为了让家里的所有设备（包括虚拟机里的 Linux 和主控机 Windows）无需安装任何代理软件就能翻墙，我们将设备的网关和 DNS 都指向了旁路由（<code>192.168.x.x</code>）。 结果配置完之后，设备不仅没翻出去，连国内网站也打不开了，彻底断网。</p><p><strong>排查过程</strong>： 来来回回测试了很久，最后通过命令行抓包发现，所有流量都被网关拦截，并返回了 <code>HTTP 407 Proxy Authentication Required</code> 错误。</p><p><strong>避坑指南</strong>： 如果你在 OpenClash 中开启了“允许局域网连接”，<strong>千万不要在底下的“HTTP 代理端口认证”里填写账号和密码</strong>。一旦开启了认证，局域网内的设备如果没有在请求头里带上密码，流量就会被静默丢弃，导致彻底断网。 解决办法：清空账号密码，让局域网流量无条件通行。</p><h2 id="_2-linux-虚拟机的网关遗漏症" tabindex="-1">2. Linux 虚拟机的网关遗漏症 <a class="header-anchor" href="#_2-linux-虚拟机的网关遗漏症" aria-label="Permalink to &quot;2. Linux 虚拟机的网关遗漏症&quot;">​</a></h2><p><strong>场景还原</strong>： 在 PVE 宿主机上开了一台 Ubuntu 虚拟机用来跑 AI 助手（OpenClaw）。旁路由配置好后，Windows 主机上网很爽，但 Ubuntu 里的 AI 助手死活查不了网页，报错请求超时。</p><p><strong>排查过程</strong>： 一开始以为是 Docker 容器网络问题，来回改 Docker 的 DNS。最后发现是 Ubuntu 系统底层的网关没指过去。</p><p><strong>避坑指南</strong>： 在 Linux 环境下，配置透明代理一定要去修改网络配置文件（比如 Ubuntu 的 Netplan 配置：<code>/etc/netplan/00-installer-config.yaml</code>）。 确保 <code>gateway4</code>（或 <code>routes</code>） 指向旁路由，且 <code>nameservers</code> 的 <code>addresses</code> 也必须是旁路由 IP。修改完必须运行 <code>sudo netplan apply</code>，否则系统底层的流量根本不知道该往哪走。</p>',10)])])}const h=o(r,[["render",s]]);export{_ as __pageData,h as default};
